INSERT INTO `academic_programs_tbl` (`id`, `program_title`, `slug`, `short_description`, `note`, `programImage`, `added_date`, `status`) VALUES
	(1, 'B.Ed Primary Education', 'bed-primary-education', 'Bachelor in Primary Education', '<p></p><p>B.Ed. in Primary Education is a Bachelor of Education degree specifically designed for aspiring teachers who want to work with young learners in primary schools.</p>This program equips students with the foundational knowledge, pedagogical skills, and practical experience necessary to excel in the field of primary education.<p><br /></p><p><b>Key Features and Benefits:</b></p><ul><li><p><b>Comprehensive Curriculum:</b> Covers a wide range of subjects, including child development, educational psychology, curriculum design, teaching methodologies, classroom management, and assessment strategies tailored to the primary level.</p><p><br /></p><p><b>Practical Experience:</b> Involves hands-on teaching experiences through student teaching placements in real primary school settings, allowing students to apply their theoretical knowledge in a practical environment.</p><p><br /></p><p><b>Focus on Young Learners:</b> Emphasizes understanding the unique developmental needs, learning styles, and interests of young children, enabling teachers to create engaging and effective learning experiences.</p><p><br /></p><p><b>Career Preparation:</b> Prepares graduates for diverse career paths in primary education, including teaching in public or private schools, working as educational consultants, curriculum developers, or pursuing further studies in education.</p><p><br /></p><p><b>Typical Coursework:</b></p><ul><li><p>Child Growth and Development</p></li><li><p>Educational Psychology</p></li><li><p>Curriculum Development and Instruction</p></li><li><p>Classroom Management and Organization</p></li><li><p>Assessment and Evaluation</p></li><li><p>Literacy and Language Arts</p></li><li><p>Mathematics</p></li><li><p>Science</p></li><li><p>Social Studies</p></li><li><p>Arts and Physical Education</p></li><li><p>Special Education</p></li><li><p>Technology Integration</p></li></ul><p><b>Career Prospects:</b></p><ul><li><p>Primary School Teacher</p></li><li><p>Educational Consultant</p></li><li><p>Curriculum Developer</p></li><li><p>School Administrator</p></li><li><p>Special Education Teacher</p></li><li><p>Educational Researcher</p></li></ul></li></ul>', 'php/uploads/courses/WhatsApp Image 2025-12-10 at 9.22.11 AM.jpeg', '2025-07-28 18:30:43', 'active'),
	(2, 'B.Ed Early Grade Education', 'bed-early-grade-education', 'Bachelor in Early Grade Education', '<h2>B.Ed Early Grade Education</h2><p><b><br /></b></p><p><b>B.Ed. in Early Grade Education</b></p><p>A Bachelor of Education (B.Ed.) in Early Grade Education is a specialized program designed for individuals who are passionate about teaching young children, typically from kindergarten through the early elementary grades (usually up to third grade). This program focuses on the crucial early years of a child\'s education, laying a strong foundation for their future academic and personal success.</p><p><br /></p><p><b>Practical Experience:</b> Involves hands-on teaching experiences through student teaching placements in real early grade classrooms, allowing students to apply their theoretical knowledge in a practical setting.</p><p><br /></p><p><b>Focus on Young Learners:</b> Emphasizes understanding the unique developmental needs, learning styles, and interests of young children, enabling teachers to create engaging and effective learning experiences.</p><p><br /></p><p><b>Career Preparation:</b> Prepares graduates for diverse career paths in early childhood education, including:</p><p><br /></p><p></p><p></p><ul><li>Early Grade Teacher</li></ul><p></p><p>Curriculum Developer</p><p></p><p>Educational Consultant</p><p></p><p>Child Care Center Director</p><p></p><p>Special Education Teacher</p><p></p><p>Educational Researcher</p><p><br /></p><p><br /></p><p>To apply you are required to possess Six (6) subjects comprising three (3) Core subjects, including English Language, Mathematics, Integrated Science/Social Studies, plus three (3) relevant elective subjects.</p><p><br /></p>', 'php/uploads/courses/campus2.png', '2025-07-28 18:43:12', 'active'),
	(3, 'B.Ed Junior High School Education', 'bed-junior-high-school-education', 'B.Ed JHS Education', '<p><b>B.Ed. in JHS Education</b></p><p>A Bachelor of Education (B.Ed.) in Junior High School (JHS) Education is a specialized program designed for individuals who aspire to become teachers at the Junior High School level. This program focuses on equipping aspiring educators with the necessary knowledge, skills, and pedagogical approaches to effectively teach and support students in their JHS years.</p><p><br /></p><p><b>B.Ed. in JHS Education</b></p><p>A Bachelor of Education (B.Ed.) in Junior High School (JHS) Education is a specialized program designed for individuals who aspire to become teachers at the JHS level in Ghana. This program focuses on equipping aspiring educators with the necessary knowledge, skills, and pedagogical approaches to effectively teach and support students in their JHS years.</p><p><br /></p><p></p><p><b>Key Features and Benefits:</b></p><ul><li><p><b>Comprehensive Curriculum:</b> Covers a wide range of subjects taught in JHS, including mathematics, English language, integrated science, social studies, and vocational skills. Additionally, courses in pedagogy, assessment and evaluation, classroom management, and educational psychology are incorporated to enhance teaching effectiveness.</p><p><br /></p><p></p></li><li><p><b>Focus on JHS Students:</b> Emphasizes understanding the unique developmental needs, learning styles, and interests of JHS students, enabling teachers to create engaging and effective learning experiences.</p><p><br /></p></li><li><p><b>Practical Experience:</b> Involves hands-on teaching experiences through student teaching placements in real JHS classrooms, allowing students to apply their theoretical knowledge and develop effective instructional strategies.</p><p><br /></p><p><b>Career Preparation:</b> Prepares graduates for diverse career paths in JHS education, including:</p><ul><li><p>JHS Teacher (in various subject areas)</p></li><li><p>Curriculum Developer</p></li><li><p>Educational Consultant</p></li><li><p>School Administrator</p></li><li><p>Tutoring and Private Teaching</p></li></ul></li></ul>', 'php/uploads/courses/1.jpg', '2025-09-01 05:03:34', 'active'),
	(1, 'B.Ed Primary Education', 'bed-primary-education', 'Bachelor in Primary Education', '<p></p><p>B.Ed. in Primary Education is a Bachelor of Education degree specifically designed for aspiring teachers who want to work with young learners in primary schools.</p>This program equips students with the foundational knowledge, pedagogical skills, and practical experience necessary to excel in the field of primary education.<p><br /></p><p><b>Key Features and Benefits:</b></p><ul><li><p><b>Comprehensive Curriculum:</b> Covers a wide range of subjects, including child development, educational psychology, curriculum design, teaching methodologies, classroom management, and assessment strategies tailored to the primary level.</p><p><br /></p><p><b>Practical Experience:</b> Involves hands-on teaching experiences through student teaching placements in real primary school settings, allowing students to apply their theoretical knowledge in a practical environment.</p><p><br /></p><p><b>Focus on Young Learners:</b> Emphasizes understanding the unique developmental needs, learning styles, and interests of young children, enabling teachers to create engaging and effective learning experiences.</p><p><br /></p><p><b>Career Preparation:</b> Prepares graduates for diverse career paths in primary education, including teaching in public or private schools, working as educational consultants, curriculum developers, or pursuing further studies in education.</p><p><br /></p><p><b>Typical Coursework:</b></p><ul><li><p>Child Growth and Development</p></li><li><p>Educational Psychology</p></li><li><p>Curriculum Development and Instruction</p></li><li><p>Classroom Management and Organization</p></li><li><p>Assessment and Evaluation</p></li><li><p>Literacy and Language Arts</p></li><li><p>Mathematics</p></li><li><p>Science</p></li><li><p>Social Studies</p></li><li><p>Arts and Physical Education</p></li><li><p>Special Education</p></li><li><p>Technology Integration</p></li></ul><p><b>Career Prospects:</b></p><ul><li><p>Primary School Teacher</p></li><li><p>Educational Consultant</p></li><li><p>Curriculum Developer</p></li><li><p>School Administrator</p></li><li><p>Special Education Teacher</p></li><li><p>Educational Researcher</p></li></ul></li></ul>', 'php/uploads/courses/WhatsApp Image 2025-12-10 at 9.22.11 AM.jpeg', '2025-07-28 18:30:43', 'active'),
	(2, 'B.Ed Early Grade Education', 'bed-early-grade-education', 'Bachelor in Early Grade Education', '<h2>B.Ed Early Grade Education</h2><p><b><br /></b></p><p><b>B.Ed. in Early Grade Education</b></p><p>A Bachelor of Education (B.Ed.) in Early Grade Education is a specialized program designed for individuals who are passionate about teaching young children, typically from kindergarten through the early elementary grades (usually up to third grade). This program focuses on the crucial early years of a child\'s education, laying a strong foundation for their future academic and personal success.</p><p><br /></p><p><b>Practical Experience:</b> Involves hands-on teaching experiences through student teaching placements in real early grade classrooms, allowing students to apply their theoretical knowledge in a practical setting.</p><p><br /></p><p><b>Focus on Young Learners:</b> Emphasizes understanding the unique developmental needs, learning styles, and interests of young children, enabling teachers to create engaging and effective learning experiences.</p><p><br /></p><p><b>Career Preparation:</b> Prepares graduates for diverse career paths in early childhood education, including:</p><p><br /></p><p></p><p></p><ul><li>Early Grade Teacher</li></ul><p></p><p>Curriculum Developer</p><p></p><p>Educational Consultant</p><p></p><p>Child Care Center Director</p><p></p><p>Special Education Teacher</p><p></p><p>Educational Researcher</p><p><br /></p><p><br /></p><p>To apply you are required to possess Six (6) subjects comprising three (3) Core subjects, including English Language, Mathematics, Integrated Science/Social Studies, plus three (3) relevant elective subjects.</p><p><br /></p>', 'php/uploads/courses/campus2.png', '2025-07-28 18:43:12', 'active'),
	(3, 'B.Ed Junior High School Education', 'bed-junior-high-school-education', 'B.Ed JHS Education', '<p><b>B.Ed. in JHS Education</b></p><p>A Bachelor of Education (B.Ed.) in Junior High School (JHS) Education is a specialized program designed for individuals who aspire to become teachers at the Junior High School level. This program focuses on equipping aspiring educators with the necessary knowledge, skills, and pedagogical approaches to effectively teach and support students in their JHS years.</p><p><br /></p><p><b>B.Ed. in JHS Education</b></p><p>A Bachelor of Education (B.Ed.) in Junior High School (JHS) Education is a specialized program designed for individuals who aspire to become teachers at the JHS level in Ghana. This program focuses on equipping aspiring educators with the necessary knowledge, skills, and pedagogical approaches to effectively teach and support students in their JHS years.</p><p><br /></p><p></p><p><b>Key Features and Benefits:</b></p><ul><li><p><b>Comprehensive Curriculum:</b> Covers a wide range of subjects taught in JHS, including mathematics, English language, integrated science, social studies, and vocational skills. Additionally, courses in pedagogy, assessment and evaluation, classroom management, and educational psychology are incorporated to enhance teaching effectiveness.</p><p><br /></p><p></p></li><li><p><b>Focus on JHS Students:</b> Emphasizes understanding the unique developmental needs, learning styles, and interests of JHS students, enabling teachers to create engaging and effective learning experiences.</p><p><br /></p></li><li><p><b>Practical Experience:</b> Involves hands-on teaching experiences through student teaching placements in real JHS classrooms, allowing students to apply their theoretical knowledge and develop effective instructional strategies.</p><p><br /></p><p><b>Career Preparation:</b> Prepares graduates for diverse career paths in JHS education, including:</p><ul><li><p>JHS Teacher (in various subject areas)</p></li><li><p>Curriculum Developer</p></li><li><p>Educational Consultant</p></li><li><p>School Administrator</p></li><li><p>Tutoring and Private Teaching</p></li></ul></li></ul>', 'php/uploads/courses/1.jpg', '2025-09-01 05:03:34', 'active');
INSERT INTO `accomodation_tbl_old` (`id`, `note`, `added_date`, `status`) VALUES
	(10, '<p>“Together we\r\n stand, divided we fall” is an adage that underscores the importance of \r\nunity. This desire for a united front birthed the Students’ \r\nRepresentative Council (SRC) as a common platform for the collective \r\nrepresentation of students in decision-making. The SRC became a force to\r\n reckon with in the era of military dictatorships as they voiced the \r\nconcerns of the masses.</p><p>Today, the SRC has grown to embrace many \r\nmore responsibilities and is considered a development partner, in \r\naddition to the earlier mandate of representing the students’ interests.\r\n Seventh-day Adventist College of Education Agona-Ashanti’s SRC concerns\r\n all aspects of students’ welfare within the college. In addition to \r\nthat, it coordinates the activities of academic, cultural, religious, \r\npolitical, and recreational clubs and societies. It also links students \r\nwith external organizations.</p><p>Immediately an individual becomes a \r\nregistered student of the seventh day Adventist College of Education, \r\nthat person automatically becomes a member of the SRC. Therefore, all \r\nstudents are eligible and encouraged to participate in one or more of \r\nthe various programs and events of the SRC.</p><p><br /></p>', '2025-08-09 02:53:28', 'active');
INSERT INTO `admission_criteria_tbl` (`id`, `title`, `description`, `status`) VALUES
	(1, 'A. WASSCE /SSSCE APPLICANTS', '<p><b>A. WASSCE /SSSCE Applicants\n</b>The general admission requirements into the 4-Year Bachelor of Education\n(B.Ed) Programme are as follows:\n</p><p><b>i. WASSCE Holders:</b> </p><p>CREDIT PASSES (A1-C6) in six (6) subjects\ncomprising Three (3) Core subjects, including English Language,\nCore Mathematics, Integrated Science or Social Studies and Three\n(3) Elective subjects relevant to the course of study.\n</p><p><b>ii. SSSCE Holders:</b></p><p>CREDIT PASSES (A-D) in six (6) subjects comprising Three\n(3) Core subjects, including English Language, Core Mathematics, Integrated\nScience or Social Studies, and Three (3) Elective subjects relevant to the\ncourse of study.\nNote: Candidates who are yet to write either the 2026 WASSCE or TVET\nCertificate II Examinations can also apply as awaiting result applicants.\n</p><p><br /></p><p><b>B. General Certificate of Education (GCE) Advance Level Applicants</b>.\n</p><p>Applicants must:\nHave passes in three (3) subjects (at least, one of the passes should be Grade\nD or better), and also have credit passes (Grade 6) in five GCE Ordinary Level\nsubjects including English Language, Mathematics, and a Science subject\nor a Social Science subject.</p><p><br /></p><p><b>C. Advanced Business Certificate Examination (ABCE) Applicants.       </b></p><p>Applicants must:\nHave passes in three (3) subjects (at least, one of the passes should be\nGrade D or better).\nHave credit passes in five (5) subjects, including English Language,\nMathematics, Integrated Science or Social Studies in the General Business\nCertificate Examination (GBCE).</p><p><br /></p><p><b>D. Technical and Vocational Education and Training (TVET) Applicants</b></p><p>Applicants must:\n</p><p>i. Have TVET Certificate II Examinations with Lower Credit (C-) or\nbetter in six (6) subjects made up of three (3) core subjects which\ninclude English, Mathematics, Integrated Science or Social Studies,\nand three (3) relevant Elective Subjects.\n</p><p>ii. Possess Certificate II in three (3) relevant trade areas awarded by\nTechnical Examinations Unit (TEU), National Vocational Training\nInstitute (NVTI), City &amp; Guilds, and other authorised awarding\nbodies in addition to NABPTEX Certificate II in lieu of passes in\nEnglish and Mathematics.\n</p><p>iii. Have National Board for Professional and Technicians Examinations\n(NABPTEX) certificate II in relevant trade areas in addition to three\n(3) credit passes in WASSCE/SSSCE core subjects, including English\nand Mathematics.\n</p><p>iv. Possess a National Certificate II qualification in Competency Based\nTraining (CBT) in a relevant trade area awarded by TEU) on the\nNational TVET Qualification Framework (NTVETQF).\n</p><p><b>E. Foreign Qualifications</b>\n</p><p>All foreign qualifications should be referred to the Ghana Tertiary Education\nCommission (GTEC) for the determination of equivalences and eligibility for\nadmission into the Colleges of Education in Ghana.\nNote: The American SAT, TOEFL, etc. cannot in themselves be acceptable as\nentry qualifications into Ghanaian tertiary educational institutions.</p><p><br /></p>', 'active'),
	(2, 'B. General Certificate of Education  (GCE) Advance Level Applicants', '<p>Applicants must: Have passes in three (3) subjects (at least, one of the passes should be Grade D or better), and also have credit passes (Grade 6) in five GCE Ordinary Level subjects including English Language, Mathematics, and a Science subject or a Social Science subject.</p>', 'active'),
	(3, 'C. Advanced Business Certificate Examination (ABCE) Applicants ', '<p>Applicants must: Have passes in three (3) subjects (at least, one of the passes should be Grade D or better). Have credit passes in five (5) subjects, including English Language, Mathematics, Integrated Science or Social Studies in the General Business Certificate Examination (GBCE).</p>', 'active'),
	(4, 'D. TVET Applicants.', '<p>Applicants must:</p><p>i. Have TVET Certificate II Examinations with Lower Credit (C-) or better in six (6) subjects made up of three (3) core subjects which include English, Mathematics, Integrated Science or Social Studies, and three (3) relevant Elective Subjects.</p><p>ii. Possess Certificate II in three (3) relevant trade areas awarded by Technical Examinations Unit (TEU), National Vocational Training Institute (NVTI), City &amp; Guilds, and other authorised awarding bodies in addition to NABPTEX Certificate II in lieu of passes in English and Mathematics.</p><p>iii. Have National Board for Professional and Technicians Examinations (NABPTEX) certificate II in relevant trade areas in addition to three (3) credit passes in WASSCE/SSSCE core subjects, including English and Mathematics.</p><p>iv. Possess a National Certificate II qualification in Competency Based Training (CBT) in a relevant trade area awarded by TEU) on the National TVET Qualification Framework (NTVETQF).</p>', 'active');
