INSERT INTO `application_procedures_tbl` (`id`, `category`, `description`, `status`) VALUES
	(1, 'Online Application Process', '<p><b>Online Application Procedure:\n</b></p><p>a. Applicants can make a payment of Three Hundred and Fifty Ghana Cedis\n(GHS350.00) into the Colleges of Education, Ghana Account at any Branch\nof the Consolidated Bank, Ghana (CBG) Limited.\n</p><p>b. Applicants can also make payment through mobile money wallet: Tigo\nCash, Telecel (Vodafone) cash, Airtel Money, and MTN Mobile Money by\ndialing short code *924*8# from all networks.</p>', 'active'),
	(2, 'Login Credential', '<p><b>Upon payment, applicants will receive the following key information:\n</b></p><p><b>a. Personal Identification Number (PIN).\n</b></p><p><b>b. An Admission Application Serial Number.\n</b></p><p><b>c. The Admission Website Address: https://admission.coeportal.edu.gh</b></p>', 'active'),
	(3, 'Guidelines for completing the Online Application Process', '<p>• Applicants should use the PIN to visit the Colleges of Education\nadmission website <a href="https://admission.coeportal.edu.gh/index.html">https://admission.coeportal.edu.gh/index.html</a><a href="https://admission.coeportal.edu.gh/index.html"></a> and follow\nspecific guidelines to fill the online application form.</p><p>• Applicants are advised to read and ensure that they fully understand\nall relevant instructions especially programmes offered in a particular\ncollege before completing the application form.\n</p><p>• Applicants are to note that application forms which are not properly\ncompleted will not be processed.\n</p><p>• Applicants should select 1\nst, 2nd, and 3rd choice of three Colleges of\nEducation in order of their preference for their programme of study,\nand must select any one of the Ghanaian languages offered in a\nparticular college.\n</p><p>• After completing the online application form, an applicant will need to\nprint a copy which should be sent with one passport photograph and a\ncopy/copies of their results slip(s) (where available) by EMS priority\nenvelope obtainable from Ghana Post nation wide and addressed to:\n</p><p>The Principal</p><p>Seventh-day Adventist College of Education, Asokore                                                                                    P.O. Box AS 18                                                                                                                                                  Asokore-Koforidua</p><p>• Applicants will be notified of the receipt of their applications by SMS\n(text message) and should therefore provide correct and reliable\nmobile phone numbers when completing the application form\nonline.\n</p><p>• Successful Applicants will receive admission offer notifications by\nSMS through their phone number provided during the application\nprocess.\n</p><p>• Applicants are to note that the Colleges of Education will verify their\nresults from the West African Examinations Council (WAEC) as part of\nthe admission process. Applicants found to have submitted fake or\nfalsified documents in support of their applications will be made to\nface the legal consequences of their actions.</p>', 'active');
